-- ============================================================================
-- Quiz Seed: 2 Corinthians — Part 1 (Chapters 1–7)
-- 3 difficulties × 7 chapters = 112 total questions
--   kids:   3 per chapter  = 21
--   teens:  5 per chapter  = 35
--   adults: 8 per chapter  = 56
-- ============================================================================

-- ═══════════════ CHAPTERS 1–5 ═══════════════

-- ═══ 2 Corinthians Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Corinthians', 1, 'kids', 1, 'Who wrote this letter?', 'Paul', 'Peter', 'James', 'John', 'a', '2 Corinthians 1:1 — "Paul, an apostle of Jesus Christ by the will of God."'),
('2 Corinthians', 1, 'kids', 2, 'What does God do for us when we are in trouble?', 'He comforts us', 'He ignores us', 'He punishes us', 'He leaves us alone', 'a', '2 Corinthians 1:4 — "Who comforteth us in all our tribulation."'),
('2 Corinthians', 1, 'kids', 3, 'Who was with Paul when he wrote this letter?', 'Timothy', 'Moses', 'David', 'Abraham', 'a', '2 Corinthians 1:1 — "Paul, an apostle of Jesus Christ by the will of God, and Timothy our brother."'),
-- Teens
('2 Corinthians', 1, 'teens', 1, 'What title does Paul give God in verse 3?', 'The Father of mercies and the God of all comfort', 'The God of thunder and lightning', 'The Lord of armies and battles', 'The King of all earthly kingdoms', 'a', '2 Corinthians 1:3 — "Blessed be God, even the Father of our Lord Jesus Christ, the Father of mercies, and the God of all comfort."'),
('2 Corinthians', 1, 'teens', 2, 'Why does God comfort us in our tribulation?', 'That we may be able to comfort them which are in any trouble, by the comfort wherewith we ourselves are comforted of God', 'So we can boast about our strength', 'So we can avoid all future suffering', 'So we never have to help anyone else', 'a', '2 Corinthians 1:4 — "Who comforteth us in all our tribulation, that we may be able to comfort them which are in any trouble, by the comfort wherewith we ourselves are comforted of God."'),
('2 Corinthians', 1, 'teens', 3, 'What happened to Paul in Asia?', 'He was pressed out of measure, above strength, insomuch that he despaired even of life', 'He built a great church with many members', 'He found a treasure of gold and silver', 'He was crowned king of the province', 'a', '2 Corinthians 1:8 — "For we would not, brethren, have you ignorant of our trouble which came to us in Asia, that we were pressed out of measure, above strength, insomuch that we despaired even of life."'),
('2 Corinthians', 1, 'teens', 4, 'Why did Paul receive the sentence of death in himself?', 'That he should not trust in himself but in God which raiseth the dead', 'To make him give up his ministry', 'To punish him for past sins', 'To test his physical endurance', 'a', '2 Corinthians 1:9 — "But we had the sentence of death in ourselves, that we should not trust in ourselves, but in God which raiseth the dead."'),
('2 Corinthians', 1, 'teens', 5, 'What has God given as an earnest (guarantee) in our hearts?', 'The Spirit — God hath sealed us and given the earnest of the Spirit in our hearts', 'A written contract of salvation', 'Gold and silver as a deposit', 'A promise from the angels', 'a', '2 Corinthians 1:22 — "Who hath also sealed us, and given the earnest of the Spirit in our hearts."'),
-- Adults
('2 Corinthians', 1, 'adults', 1, 'How does Paul describe the relationship between Christ''s sufferings and comfort?', 'As the sufferings of Christ abound in us, so our consolation also aboundeth by Christ', 'Suffering and comfort are unrelated experiences', 'Comfort comes only after all suffering has ended', 'Christ''s sufferings eliminate the need for human suffering', 'a', '2 Corinthians 1:5 — "For as the sufferings of Christ abound in us, so our consolation also aboundeth by Christ."'),
('2 Corinthians', 1, 'adults', 2, 'What does Paul say about all the promises of God?', 'In him they are yea, and in him Amen, unto the glory of God by us', 'They are conditional upon perfect obedience', 'They apply only to the apostles', 'They are symbolic and not literal', 'a', '2 Corinthians 1:20 — "For all the promises of God in him are yea, and in him Amen, unto the glory of God by us."'),
('2 Corinthians', 1, 'adults', 3, 'Who does Paul say establishes believers in Christ and has anointed them?', 'God — who also hath sealed us and given the earnest of the Spirit', 'The apostles through their teaching', 'The law of Moses through obedience', 'The church through baptism', 'a', '2 Corinthians 1:21-22 — "Now he which stablisheth us with you in Christ, and hath anointed us, is God; Who hath also sealed us, and given the earnest of the Spirit in our hearts."'),
('2 Corinthians', 1, 'adults', 4, 'Why did Paul call God as a witness upon his soul?', 'To spare them he came not as yet unto Corinth — not because he had dominion over their faith but was a helper of their joy', 'Because he was afraid of the journey', 'Because he wanted to visit Rome first', 'Because the Corinthians owed him money', 'a', '2 Corinthians 1:23-24 — "Moreover I call God for a record upon my soul, that to spare you I came not as yet unto Corinth. Not for that we have dominion over your faith, but are helpers of your joy."'),
('2 Corinthians', 1, 'adults', 5, 'What does Paul say about the Corinthians'' standing in faith?', 'By faith ye stand — he is not lord over their faith but a helper of their joy', 'They are weak and falling away', 'They need Paul to sustain their faith', 'They have no faith of their own', 'a', '2 Corinthians 1:24 — "Not for that we have dominion over your faith, but are helpers of your joy: for by faith ye stand."'),
('2 Corinthians', 1, 'adults', 6, 'What does Paul mean by saying he had the "sentence of death" in himself?', 'He had given up hope of survival humanly speaking, so that he would learn to trust only in God who raises the dead', 'He was formally sentenced to execution by a Roman court', 'He was suffering from a terminal illness', 'He was feeling depressed about his ministry', 'a', '2 Corinthians 1:9 — "But we had the sentence of death in ourselves, that we should not trust in ourselves, but in God which raiseth the dead."'),
('2 Corinthians', 1, 'adults', 7, 'What role does Paul say the Corinthians play in his deliverance?', 'They help together by prayer for him, so that thanks may be given by many persons on his behalf', 'They send him financial support', 'They send bodyguards to protect him', 'They write letters to the Roman authorities', 'a', '2 Corinthians 1:11 — "Ye also helping together by prayer for us, that for the gift bestowed upon us by the means of many persons thanks may be given by many on our behalf."'),
('2 Corinthians', 1, 'adults', 8, 'What does Paul say his rejoicing and the testimony of his conscience is?', 'That in simplicity and godly sincerity, not with fleshly wisdom but by the grace of God, he had his conversation in the world', 'That he performed many miracles', 'That he converted the most people', 'That he had the most theological knowledge', 'a', '2 Corinthians 1:12 — "For our rejoicing is this, the testimony of our conscience, that in simplicity and godly sincerity, not with fleshly wisdom, but by the grace of God, we have had our conversation in the world, and more abundantly to you-ward."');

-- ═══ 2 Corinthians Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Corinthians', 2, 'kids', 1, 'What did Paul write to the Corinthians with?', 'Many tears and a loving heart', 'Anger and frustration', 'Happiness and laughter', 'Fear and worry', 'a', '2 Corinthians 2:4 — "For out of much affliction and anguish of heart I wrote unto you with many tears."'),
('2 Corinthians', 2, 'kids', 2, 'What should we do when someone is sorry for what they did wrong?', 'Forgive them and comfort them', 'Stay angry at them forever', 'Ignore them completely', 'Make them feel worse', 'a', '2 Corinthians 2:7 — "So that contrariwise ye ought rather to forgive him, and comfort him, lest perhaps such a one should be swallowed up with overmuch sorrow."'),
('2 Corinthians', 2, 'kids', 3, 'What does God always cause us to do in Christ?', 'Triumph (win)', 'Fail', 'Hide', 'Run away', 'a', '2 Corinthians 2:14 — "Now thanks be unto God, which always causeth us to triumph in Christ."'),
-- Teens
('2 Corinthians', 2, 'teens', 1, 'Why did Paul write with tears instead of visiting?', 'He did not want to come again to them in heaviness, but wrote that his joy might be theirs', 'He was too busy with other churches', 'He was forbidden by the authorities', 'He had lost interest in the Corinthians', 'a', '2 Corinthians 2:1,3 — "But I determined this with myself, that I would not come again to you in heaviness... that my joy is the joy of you all."'),
('2 Corinthians', 2, 'teens', 2, 'Why should the Corinthians forgive the offender?', 'Lest Satan should get an advantage of them, for we are not ignorant of his devices', 'Because the offender was an important person', 'Because Paul would punish them if they didn''t', 'Because forgiveness earns heavenly rewards', 'a', '2 Corinthians 2:10-11 — "Lest Satan should get an advantage of us: for we are not ignorant of his devices."'),
('2 Corinthians', 2, 'teens', 3, 'What does Paul call the knowledge of Christ?', 'A sweet savour — God maketh manifest the savour of his knowledge by us in every place', 'A heavy burden to carry', 'A mystery no one can understand', 'A secret for apostles only', 'a', '2 Corinthians 2:14 — "Now thanks be unto God, which always causeth us to triumph in Christ, and maketh manifest the savour of his knowledge by us in every place."'),
('2 Corinthians', 2, 'teens', 4, 'What is the gospel to those who are saved versus those who perish?', 'To one a savour of death unto death, and to the other a savour of life unto life', 'The same pleasant message to everyone', 'Confusing to both groups equally', 'Only meaningful to educated people', 'a', '2 Corinthians 2:15-16 — "For we are unto God a sweet savour of Christ, in them that are saved, and in them that perish: To the one we are the savour of death unto death; and to the other the savour of life unto life."'),
('2 Corinthians', 2, 'teens', 5, 'What does Paul say they are NOT doing with the word of God?', 'They are not as many, which corrupt the word of God, but speak in sincerity as of God in the sight of God', 'They are not reading it enough', 'They are not translating it properly', 'They are not memorizing it daily', 'a', '2 Corinthians 2:17 — "For we are not as many, which corrupt the word of God: but as of sincerity, but as of God, in the sight of God speak we in Christ."'),
-- Adults
('2 Corinthians', 2, 'adults', 1, 'What was the punishment inflicted on the offender by many?', 'Sufficient punishment — Paul now urges forgiveness and comfort lest he be swallowed up with overmuch sorrow', 'A fine of money paid to the church', 'Permanent exile from the city', 'A public flogging in the synagogue', 'a', '2 Corinthians 2:6-7 — "Sufficient to such a man is this punishment, which was inflicted of many. So that contrariwise ye ought rather to forgive him, and comfort him, lest perhaps such a one should be swallowed up with overmuch sorrow."'),
('2 Corinthians', 2, 'adults', 2, 'What does Paul urge the Corinthians to confirm toward the offender?', 'Their love — that he might know the proof of them, whether they be obedient in all things', 'Their authority over him', 'Their superiority to him', 'Their indifference toward him', 'a', '2 Corinthians 2:8-9 — "Wherefore I beseech you that ye would confirm your love toward him. For to this end also did I write, that I might know the proof of you, whether ye be obedient in all things."'),
('2 Corinthians', 2, 'adults', 3, 'In whose person does Paul say he forgave?', 'In the person of Christ — what he forgave, he forgave for their sakes in the person of Christ', 'In the person of Moses', 'In the person of the high priest', 'In his own person as an apostle', 'a', '2 Corinthians 2:10 — "To whom ye forgive any thing, I forgive also: for if I forgave any thing, to whom I forgave it, for your sakes forgave I it in the person of Christ."'),
('2 Corinthians', 2, 'adults', 4, 'What happened when Paul came to Troas to preach?', 'A door was opened unto him of the Lord, but he had no rest in his spirit because he found not Titus', 'He was arrested and imprisoned', 'He performed many miracles', 'He found a large congregation waiting', 'a', '2 Corinthians 2:12-13 — "Furthermore, when I came to Troas to preach Christ''s gospel, and a door was opened unto me of the Lord, I had no rest in my spirit, because I found not Titus my brother."'),
('2 Corinthians', 2, 'adults', 5, 'What profound question does Paul ask in verse 16?', 'Who is sufficient for these things? — referring to the weighty responsibility of being a savour of life or death', 'How many churches should one apostle oversee?', 'When will Christ return to earth?', 'Where should the next church be planted?', 'a', '2 Corinthians 2:16 — "And who is sufficient for these things?"'),
('2 Corinthians', 2, 'adults', 6, 'What does Paul mean by those who "corrupt" the word of God?', 'Those who peddle or adulterate God''s word for profit, as opposed to speaking sincerely as from God in Christ', 'Those who accidentally misquote Scripture', 'Those who translate it into other languages', 'Those who read it without understanding', 'a', '2 Corinthians 2:17 — "For we are not as many, which corrupt the word of God: but as of sincerity, but as of God, in the sight of God speak we in Christ."'),
('2 Corinthians', 2, 'adults', 7, 'Why did Paul leave Troas despite the open door for the gospel?', 'He had no rest in his spirit because he did not find Titus, so he went into Macedonia', 'The authorities shut down his preaching', 'He ran out of money for the journey', 'The church at Troas rejected his message', 'a', '2 Corinthians 2:13 — "I had no rest in my spirit, because I found not Titus my brother: but taking my leave of them, I went from thence into Macedonia."'),
('2 Corinthians', 2, 'adults', 8, 'What does Paul say about their manner of speaking in the sight of God?', 'As of sincerity, as of God, in the sight of God speak we in Christ — transparent accountability before God', 'They speak with great eloquence and rhetoric', 'They speak only when inspired by visions', 'They speak with the authority of the Sanhedrin', 'a', '2 Corinthians 2:17 — "But as of sincerity, but as of God, in the sight of God speak we in Christ."');

-- ═══ 2 Corinthians Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Corinthians', 3, 'kids', 1, 'What does Paul call the Corinthian believers?', 'His letter, written in their hearts', 'His students in a school', 'His soldiers in an army', 'His servants in a palace', 'a', '2 Corinthians 3:2 — "Ye are our epistle written in our hearts, known and read of all men."'),
('2 Corinthians', 3, 'kids', 2, 'What does the Spirit give?', 'Life', 'Rules', 'Punishment', 'Fear', 'a', '2 Corinthians 3:6 — "The letter killeth, but the spirit giveth life."'),
('2 Corinthians', 3, 'kids', 3, 'Where the Spirit of the Lord is, what do we have?', 'Liberty (freedom)', 'Chains', 'Sadness', 'Darkness', 'a', '2 Corinthians 3:17 — "Where the Spirit of the Lord is, there is liberty."'),
-- Teens
('2 Corinthians', 3, 'teens', 1, 'What is the Corinthians'' epistle written with?', 'Not with ink but with the Spirit of the living God, not in tables of stone but in fleshy tables of the heart', 'With expensive gold ink on parchment', 'With ordinary ink on papyrus scrolls', 'With carved letters on marble tablets', 'a', '2 Corinthians 3:3 — "Written not with ink, but with the Spirit of the living God; not in tables of stone, but in fleshy tables of the heart."'),
('2 Corinthians', 3, 'teens', 2, 'What does the letter do versus what the spirit does?', 'The letter killeth but the spirit giveth life', 'The letter gives life but the spirit restricts', 'Both the letter and spirit give life equally', 'The letter and spirit are the same thing', 'a', '2 Corinthians 3:6 — "Who also hath made us able ministers of the new testament; not of the letter, but of the spirit: for the letter killeth, but the spirit giveth life."'),
('2 Corinthians', 3, 'teens', 3, 'What happened to Moses'' face when he came down from the mountain?', 'His face shone with glory so the children of Israel could not steadfastly behold it', 'His face turned completely white', 'His face became invisible', 'His face looked exactly the same as before', 'a', '2 Corinthians 3:7 — "The ministration of death, written and engraven in stones, was glorious, so that the children of Israel could not stedfastly behold the face of Moses for the glory of his countenance."'),
('2 Corinthians', 3, 'teens', 4, 'What is still over the hearts of Israel when Moses is read?', 'A veil — the vail is upon their heart, but when they turn to the Lord, the vail shall be taken away', 'A crown of thorns', 'A cloud of darkness', 'A wall of fire', 'a', '2 Corinthians 3:15-16 — "But even unto this day, when Moses is read, the vail is upon their heart. Nevertheless when it shall turn to the Lord, the vail shall be taken away."'),
('2 Corinthians', 3, 'teens', 5, 'What are believers being changed into?', 'The same image from glory to glory, even as by the Spirit of the Lord', 'Powerful warriors', 'Perfect scholars', 'Wealthy rulers', 'a', '2 Corinthians 3:18 — "But we all, with open face beholding as in a glass the glory of the Lord, are changed into the same image from glory to glory, even as by the Spirit of the Lord."'),
-- Adults
('2 Corinthians', 3, 'adults', 1, 'What does Paul say about needing epistles of commendation?', 'He needs no letters of commendation to or from them because they are his epistle, known and read of all men', 'He requires formal letters from every church', 'He carries letters from the Jerusalem council', 'He insists on written approval from Peter', 'a', '2 Corinthians 3:1-2 — "Do we begin again to commend ourselves? or need we, as some others, epistles of commendation to you, or letters of commendation from you? Ye are our epistle written in our hearts, known and read of all men."'),
('2 Corinthians', 3, 'adults', 2, 'What does Paul say about his sufficiency?', 'Not that we are sufficient of ourselves to think any thing as of ourselves; but our sufficiency is of God', 'His sufficiency comes from his rabbinic training', 'His sufficiency is from years of experience', 'His sufficiency is from the Jerusalem church', 'a', '2 Corinthians 3:5 — "Not that we are sufficient of ourselves to think any thing as of ourselves; but our sufficiency is of God."'),
('2 Corinthians', 3, 'adults', 3, 'How does Paul contrast the ministry of death with the ministry of the spirit?', 'If the ministration of death, written and engraven in stones, was glorious, the ministration of the spirit must be rather more glorious', 'The ministry of death was shameful and the spirit is merely adequate', 'Both ministries have equal glory', 'The old ministry was more glorious than the new', 'a', '2 Corinthians 3:7-8 — "The ministration of death, written and engraven in stones, was glorious... how shall not the ministration of the spirit be rather more glorious?"'),
('2 Corinthians', 3, 'adults', 4, 'What does Paul say about the glory of the old covenant versus the new?', 'That which was made glorious had no glory in this respect, by reason of the glory that excelleth', 'The old covenant''s glory continues unchanged', 'Both covenants share identical glory', 'The old covenant had no glory at all', 'a', '2 Corinthians 3:10 — "For even that which was made glorious had no glory in this respect, by reason of the glory that excelleth."'),
('2 Corinthians', 3, 'adults', 5, 'Why did Moses put a vail over his face?', 'So the children of Israel could not stedfastly look to the end of that which is abolished', 'To protect his face from the sun', 'To hide his identity from the people', 'To show humility before God', 'a', '2 Corinthians 3:13 — "And not as Moses, which put a vail over his face, that the children of Israel could not stedfastly look to the end of that which is abolished."'),
('2 Corinthians', 3, 'adults', 6, 'What happens when one turns to the Lord regarding the veil?', 'The vail shall be taken away — now the Lord is that Spirit, and where the Spirit of the Lord is, there is liberty', 'The veil becomes thicker', 'The veil changes colour', 'The veil is passed to someone else', 'a', '2 Corinthians 3:16-17 — "Nevertheless when it shall turn to the Lord, the vail shall be taken away. Now the Lord is that Spirit: and where the Spirit of the Lord is, there is liberty."'),
('2 Corinthians', 3, 'adults', 7, 'What does Paul mean by "beholding as in a glass the glory of the Lord"?', 'With unveiled face we reflect the Lord''s glory like a mirror and are progressively transformed into his image from glory to glory', 'We see God perfectly and completely right now', 'We see a distorted image that never changes', 'We cannot see any of God''s glory at all', 'a', '2 Corinthians 3:18 — "But we all, with open face beholding as in a glass the glory of the Lord, are changed into the same image from glory to glory, even as by the Spirit of the Lord."'),
('2 Corinthians', 3, 'adults', 8, 'What does Paul identify the "Lord" as in verse 17?', 'Now the Lord is that Spirit — identifying the Holy Spirit''s work in removing the veil and bringing freedom', 'The Lord is only the Father', 'The Lord refers to an angel', 'The Lord is a metaphor for knowledge', 'a', '2 Corinthians 3:17 — "Now the Lord is that Spirit: and where the Spirit of the Lord is, there is liberty."');

-- ═══ 2 Corinthians Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Corinthians', 4, 'kids', 1, 'What did God command to shine out of darkness?', 'Light', 'Stars', 'Fire', 'Gold', 'a', '2 Corinthians 4:6 — "For God, who commanded the light to shine out of darkness, hath shined in our hearts."'),
('2 Corinthians', 4, 'kids', 2, 'What kind of vessels (containers) does Paul say our bodies are like?', 'Earthen vessels (clay pots)', 'Gold vases', 'Silver cups', 'Diamond boxes', 'a', '2 Corinthians 4:7 — "But we have this treasure in earthen vessels, that the excellency of the power may be of God, and not of us."'),
('2 Corinthians', 4, 'kids', 3, 'Can we see the things that last forever?', 'No, eternal things are not seen; things we see are temporary', 'Yes, everything we see lasts forever', 'Only some things we see last forever', 'Nothing lasts forever at all', 'a', '2 Corinthians 4:18 — "The things which are seen are temporal; but the things which are not seen are eternal."'),
-- Teens
('2 Corinthians', 4, 'teens', 1, 'What does Paul say they have renounced?', 'The hidden things of dishonesty — not walking in craftiness nor handling the word of God deceitfully', 'The right to earn a living', 'The hope of ever visiting Corinth', 'The practice of speaking in tongues', 'a', '2 Corinthians 4:2 — "But have renounced the hidden things of dishonesty, not walking in craftiness, nor handling the word of God deceitfully."'),
('2 Corinthians', 4, 'teens', 2, 'Who has blinded the minds of those who don''t believe?', 'The god of this world — lest the light of the glorious gospel of Christ should shine unto them', 'The Roman government', 'The Jewish leaders', 'The Greek philosophers', 'a', '2 Corinthians 4:4 — "In whom the god of this world hath blinded the minds of them which believe not, lest the light of the glorious gospel of Christ, who is the image of God, should shine unto them."'),
('2 Corinthians', 4, 'teens', 3, 'Why do we have treasure in earthen vessels?', 'That the excellency of the power may be of God and not of us', 'So people will admire us', 'So we can show off our strength', 'So the vessels become more valuable', 'a', '2 Corinthians 4:7 — "But we have this treasure in earthen vessels, that the excellency of the power may be of God, and not of us."'),
('2 Corinthians', 4, 'teens', 4, 'Though we are troubled, what does Paul say we are NOT?', 'Distressed — troubled on every side yet not distressed; perplexed but not in despair', 'Troubled at all', 'Believers in Christ', 'Qualified to preach', 'a', '2 Corinthians 4:8 — "We are troubled on every side, yet not distressed; we are perplexed, but not in despair."'),
('2 Corinthians', 4, 'teens', 5, 'What does Paul say about our light affliction?', 'It worketh for us a far more exceeding and eternal weight of glory', 'It has no purpose or meaning', 'It is punishment for our sins', 'It proves God has abandoned us', 'a', '2 Corinthians 4:17 — "For our light affliction, which is but for a moment, worketh for us a far more exceeding and eternal weight of glory."'),
-- Adults
('2 Corinthians', 4, 'adults', 1, 'How does Paul describe his ministry in light of God''s mercy?', 'As we have received mercy we faint not — commending himself by manifestation of the truth to every man''s conscience in the sight of God', 'As a heavy burden he reluctantly carries', 'As a privilege reserved for the elite', 'As a temporary assignment until retirement', 'a', '2 Corinthians 4:1-2 — "Therefore seeing we have this ministry, as we have received mercy, we faint not; But have renounced the hidden things of dishonesty... by manifestation of the truth commending ourselves to every man''s conscience in the sight of God."'),
('2 Corinthians', 4, 'adults', 2, 'If the gospel is hid, to whom is it hid?', 'To them that are lost — in whom the god of this world hath blinded the minds of them which believe not', 'To the uneducated and illiterate', 'To the Gentile nations only', 'To those who live far from Jerusalem', 'a', '2 Corinthians 4:3-4 — "But if our gospel be hid, it is hid to them that are lost: In whom the god of this world hath blinded the minds of them which believe not."'),
('2 Corinthians', 4, 'adults', 3, 'Who does Paul say they preach?', 'Not ourselves but Christ Jesus the Lord, and ourselves your servants for Jesus'' sake', 'Themselves as the primary authority', 'A new philosophy of life', 'The traditions of the Jewish elders', 'a', '2 Corinthians 4:5 — "For we preach not ourselves, but Christ Jesus the Lord; and ourselves your servants for Jesus'' sake."'),
('2 Corinthians', 4, 'adults', 4, 'What has God shined in our hearts to give?', 'The light of the knowledge of the glory of God in the face of Jesus Christ', 'The ability to perform miracles', 'The wisdom of Solomon', 'The power to judge others', 'a', '2 Corinthians 4:6 — "For God, who commanded the light to shine out of darkness, hath shined in our hearts, to give the light of the knowledge of the glory of God in the face of Jesus Christ."'),
('2 Corinthians', 4, 'adults', 5, 'What fourfold description of trials does Paul give in verses 8-9?', 'Troubled but not distressed; perplexed but not in despair; persecuted but not forsaken; cast down but not destroyed', 'Hungry, thirsty, cold, and homeless', 'Beaten, imprisoned, shipwrecked, and stoned', 'Mocked, rejected, betrayed, and abandoned', 'a', '2 Corinthians 4:8-9 — "We are troubled on every side, yet not distressed; we are perplexed, but not in despair; Persecuted, but not forsaken; cast down, but not destroyed."'),
('2 Corinthians', 4, 'adults', 6, 'What does Paul say about the dying of the Lord Jesus in their body?', 'Always bearing about in the body the dying of the Lord Jesus, that the life also of Jesus might be made manifest in our body', 'It is a burden that weakens their ministry', 'It is a metaphor for emotional sadness', 'It is a reference to baptism only', 'a', '2 Corinthians 4:10 — "Always bearing about in the body the dying of the Lord Jesus, that the life also of Jesus might be made manifest in our body."'),
('2 Corinthians', 4, 'adults', 7, 'What spirit of faith does Paul reference?', 'We having the same spirit of faith according as it is written, I believed and therefore have I spoken — citing Psalm 116:10', 'A spirit of timidity and fear', 'A spirit of worldly wisdom', 'A spirit of legalistic obedience', 'a', '2 Corinthians 4:13 — "We having the same spirit of faith, according as it is written, I believed, and therefore have I spoken; we also believe, and therefore speak."'),
('2 Corinthians', 4, 'adults', 8, 'What contrast does Paul draw between the outward and inward man?', 'Though our outward man perish, yet the inward man is renewed day by day', 'Both the outward and inward man perish together', 'The outward man is strengthened while the inward weakens', 'The inward man does not change at all', 'a', '2 Corinthians 4:16 — "For which cause we faint not; but though our outward man perish, yet the inward man is renewed day by day."');

-- ═══ 2 Corinthians Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Corinthians', 5, 'kids', 1, 'What does God have waiting for us in heaven?', 'A house not made with hands, eternal in the heavens', 'A big pile of gold', 'A castle made of clouds', 'Nothing at all', 'a', '2 Corinthians 5:1 — "For we know that if our earthly house of this tabernacle were dissolved, we have a building of God, an house not made with hands, eternal in the heavens."'),
('2 Corinthians', 5, 'kids', 2, 'If anyone is in Christ, what are they?', 'A new creature — old things are passed away and all things are become new', 'The same as before', 'Older and wiser', 'Just a good person', 'a', '2 Corinthians 5:17 — "Therefore if any man be in Christ, he is a new creature: old things are passed away; behold, all things are become new."'),
('2 Corinthians', 5, 'kids', 3, 'What job has God given believers?', 'The ministry of reconciliation (bringing people back to God)', 'The job of judging everyone', 'The task of building temples', 'The work of collecting money', 'a', '2 Corinthians 5:18 — "And hath given to us the ministry of reconciliation."'),
-- Teens
('2 Corinthians', 5, 'teens', 1, 'What does Paul say about being absent from the body?', 'To be absent from the body is to be present with the Lord', 'To be absent from the body is to sleep forever', 'To be absent from the body is to cease to exist', 'To be absent from the body is to wander in darkness', 'a', '2 Corinthians 5:8 — "We are confident, I say, and willing rather to be absent from the body, and to be present with the Lord."'),
('2 Corinthians', 5, 'teens', 2, 'Where must we all appear?', 'Before the judgment seat of Christ, that every one may receive the things done in his body', 'Before the Roman senate', 'Before the Jewish Sanhedrin', 'Before the angels in heaven', 'a', '2 Corinthians 5:10 — "For we must all appear before the judgment seat of Christ; that every one may receive the things done in his body, according to that he hath done, whether it be good or bad."'),
('2 Corinthians', 5, 'teens', 3, 'What constrains (compels) Paul?', 'The love of Christ constraineth us — because if one died for all then were all dead', 'The fear of punishment', 'The desire for fame', 'The need for money', 'a', '2 Corinthians 5:14 — "For the love of Christ constraineth us; because we thus judge, that if one died for all, then were all dead."'),
('2 Corinthians', 5, 'teens', 4, 'What does "if any man be in Christ, he is a new creature" mean?', 'Old things are passed away and all things are become new — a complete spiritual transformation', 'He becomes physically different', 'He gets a new name', 'He moves to a new city', 'a', '2 Corinthians 5:17 — "Therefore if any man be in Christ, he is a new creature: old things are passed away; behold, all things are become new."'),
('2 Corinthians', 5, 'teens', 5, 'What did God do with our sins through Christ?', 'He made him to be sin for us who knew no sin, that we might be made the righteousness of God in him', 'He ignored our sins entirely', 'He gave us a list of rules to follow', 'He reduced the punishment by half', 'a', '2 Corinthians 5:21 — "For he hath made him to be sin for us, who knew no sin; that we might be made the righteousness of God in him."'),
-- Adults
('2 Corinthians', 5, 'adults', 1, 'What does Paul say about the earthly house of this tabernacle?', 'If it were dissolved, we have a building of God, an house not made with hands, eternal in the heavens', 'It will be renovated and made eternal', 'It will be transferred to another person', 'It has no relationship to the heavenly body', 'a', '2 Corinthians 5:1 — "For we know that if our earthly house of this tabernacle were dissolved, we have a building of God, an house not made with hands, eternal in the heavens."'),
('2 Corinthians', 5, 'adults', 2, 'What has God wrought (prepared) us for and what has he given as the earnest?', 'God hath wrought us for this selfsame thing and given unto us the earnest of the Spirit', 'God has prepared wealth and given us gold', 'God has wrought punishment and given a warning', 'God has wrought confusion and given us riddles', 'a', '2 Corinthians 5:5 — "Now he that hath wrought us for the selfsame thing is God, who also hath given unto us the earnest of the Spirit."'),
('2 Corinthians', 5, 'adults', 3, 'What does Paul say about walking by faith?', 'We walk by faith, not by sight — being always confident knowing that whilst in the body we are absent from the Lord', 'We walk by sight and not by faith', 'Faith and sight are identical things', 'Walking by faith means ignoring all evidence', 'a', '2 Corinthians 5:6-7 — "Therefore we are always confident, knowing that, whilst we are at home in the body, we are absent from the Lord: (For we walk by faith, not by sight.)"'),
('2 Corinthians', 5, 'adults', 4, 'What does Paul say about knowing Christ after the flesh?', 'Though we have known Christ after the flesh, yet now henceforth know we him no more — we now know him spiritually', 'We should focus only on Christ''s earthly life', 'Physical knowledge of Christ is most important', 'We never knew Christ in any way', 'a', '2 Corinthians 5:16 — "Wherefore henceforth know we no man after the flesh: yea, though we have known Christ after the flesh, yet now henceforth know we him no more."'),
('2 Corinthians', 5, 'adults', 5, 'What is the ministry of reconciliation that God has given?', 'That God was in Christ reconciling the world unto himself, not imputing their trespasses unto them, and hath committed unto us the word of reconciliation', 'A ministry of judgment and condemnation', 'A ministry limited to the Jewish people', 'A ministry of philosophical debate', 'a', '2 Corinthians 5:19 — "To wit, that God was in Christ, reconciling the world unto himself, not imputing their trespasses unto them; and hath committed unto us the word of reconciliation."'),
('2 Corinthians', 5, 'adults', 6, 'What role does Paul say believers hold?', 'Ambassadors for Christ — as though God did beseech you by us, we pray you in Christ''s stead, be ye reconciled to God', 'Judges over the nations', 'Kings of earthly kingdoms', 'Servants of the Roman government', 'a', '2 Corinthians 5:20 — "Now then we are ambassadors for Christ, as though God did beseech you by us: we pray you in Christ''s stead, be ye reconciled to God."'),
('2 Corinthians', 5, 'adults', 7, 'What is the theological significance of verse 21?', 'The great exchange: Christ, who knew no sin, was made sin for us that we might be made the righteousness of God in him — imputed righteousness', 'Christ merely demonstrated how to live righteously', 'God punished Christ for his own sins', 'Righteousness is earned through good works', 'a', '2 Corinthians 5:21 — "For he hath made him to be sin for us, who knew no sin; that we might be made the righteousness of God in him."'),
('2 Corinthians', 5, 'adults', 8, 'What does Paul labour for, whether present or absent?', 'That we may be accepted of him — we labour to be well-pleasing to the Lord', 'To build the largest church possible', 'To earn the highest heavenly reward', 'To impress the other apostles', 'a', '2 Corinthians 5:9 — "Wherefore we labour, that, whether present or absent, we may be accepted of him."');

-- ═══════════════ CHAPTERS 6–7 ═══════════════

-- ═══ 2 Corinthians Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Corinthians', 6, 'kids', 1, 'When is the right time to be saved?', 'Now — today is the day of salvation', 'Only when you are very old', 'Only on special holidays', 'Only after you die', 'a', '2 Corinthians 6:2 — "Behold, now is the accepted time; behold, now is the day of salvation."'),
('2 Corinthians', 6, 'kids', 2, 'What does God promise to be to us?', 'A Father — and we shall be his sons and daughters', 'A strict judge', 'A distant stranger', 'A harsh teacher', 'a', '2 Corinthians 6:18 — "And will be a Father unto you, and ye shall be my sons and daughters, saith the Lord Almighty."'),
('2 Corinthians', 6, 'kids', 3, 'What should believers do with people who don''t believe?', 'Not be unequally yoked (joined) together with unbelievers', 'Avoid them completely at all times', 'Do whatever they want us to do', 'Pretend to agree with everything they say', 'a', '2 Corinthians 6:14 — "Be ye not unequally yoked together with unbelievers."'),
-- Teens
('2 Corinthians', 6, 'teens', 1, 'What does Paul urge the Corinthians not to receive in vain?', 'The grace of God — for now is the accepted time, now is the day of salvation', 'Their financial gifts to the church', 'The letters Paul sent to them', 'The food provided at church meals', 'a', '2 Corinthians 6:1-2 — "We then, as workers together with him, beseech you also that ye receive not the grace of God in vain... behold, now is the accepted time; behold, now is the day of salvation."'),
('2 Corinthians', 6, 'teens', 2, 'How does Paul describe his ministry to give no offence?', 'In all things approving ourselves as ministers of God — in much patience, afflictions, necessities, distresses', 'By avoiding all difficult situations', 'By always agreeing with everyone', 'By staying silent about controversial truths', 'a', '2 Corinthians 6:4 — "But in all things approving ourselves as the ministers of God, in much patience, in afflictions, in necessities, in distresses."'),
('2 Corinthians', 6, 'teens', 3, 'What rhetorical questions does Paul ask about believers and unbelievers?', 'What fellowship hath righteousness with unrighteousness? What communion hath light with darkness?', 'How much money should they share?', 'What language should they speak together?', 'Where should they live in the same city?', 'a', '2 Corinthians 6:14 — "For what fellowship hath righteousness with unrighteousness? and what communion hath light with darkness?"'),
('2 Corinthians', 6, 'teens', 4, 'What does Paul say believers are the temple of?', 'The living God — as God hath said, I will dwell in them and walk in them', 'The temple of human achievement', 'The temple of Roman culture', 'The temple of earthly wisdom', 'a', '2 Corinthians 6:16 — "For ye are the temple of the living God; as God hath said, I will dwell in them, and walk in them; and I will be their God, and they shall be my people."'),
('2 Corinthians', 6, 'teens', 5, 'What does God tell his people to do in verse 17?', 'Come out from among them, be separate, and touch not the unclean thing — and God will receive them', 'Join every group they can find', 'Blend in with the surrounding culture', 'Fight against the Roman government', 'a', '2 Corinthians 6:17 — "Wherefore come out from among them, and be ye separate, saith the Lord, and touch not the unclean thing; and I will receive you."'),
-- Adults
('2 Corinthians', 6, 'adults', 1, 'What Old Testament passage does Paul quote in verse 2?', 'Isaiah 49:8 — "In an acceptable time have I heard thee, and in a day of salvation have I succoured thee"', 'Psalm 23:1', 'Genesis 1:1', 'Deuteronomy 6:4', 'a', '2 Corinthians 6:2 — "For he saith, I have heard thee in a time accepted, and in the day of salvation have I succoured thee." This quotes Isaiah 49:8.'),
('2 Corinthians', 6, 'adults', 2, 'What extensive catalogue of hardships does Paul list in verses 4-5?', 'Patience, afflictions, necessities, distresses, stripes, imprisonments, tumults, labours, watchings, fastings', 'Wealth, power, fame, comfort, and luxury', 'Education, travel, study, and debate', 'Health, rest, peace, and quiet', 'a', '2 Corinthians 6:4-5 — "In much patience, in afflictions, in necessities, in distresses, In stripes, in imprisonments, in tumults, in labours, in watchings, in fastings."'),
('2 Corinthians', 6, 'adults', 3, 'What paradoxes does Paul describe about the apostolic ministry in verses 8-10?', 'As unknown yet well known; dying yet living; chastened yet not killed; sorrowful yet always rejoicing; poor yet making many rich; having nothing yet possessing all things', 'As wealthy yet poor; famous yet unknown', 'As powerful yet weak; honoured yet dishonoured', 'As young yet old; travelling yet stationary', 'a', '2 Corinthians 6:8-10 — "By honour and dishonour, by evil report and good report: as deceivers, and yet true; As unknown, and yet well known; as dying, and yet, behold, we live; as chastened, and not killed; As sorrowful, yet alway rejoicing; as poor, yet making many rich; as having nothing, and yet possessing all things."'),
('2 Corinthians', 6, 'adults', 4, 'What does Paul mean by "be ye not unequally yoked together with unbelievers"?', 'Believers should not enter binding partnerships with unbelievers that compromise their faith — the metaphor is from Deuteronomy 22:10 about yoking different animals together', 'Christians should never interact with non-Christians', 'Believers should not do business of any kind', 'Only marriages between believers and unbelievers are forbidden', 'a', '2 Corinthians 6:14 — "Be ye not unequally yoked together with unbelievers: for what fellowship hath righteousness with unrighteousness?" The imagery comes from Deuteronomy 22:10.'),
('2 Corinthians', 6, 'adults', 5, 'What five rhetorical questions does Paul ask in verses 14-16?', 'What fellowship hath righteousness with unrighteousness? What communion hath light with darkness? What concord hath Christ with Belial? What part hath he that believeth with an infidel? What agreement hath the temple of God with idols?', 'Five questions about church finances', 'Five questions about eschatology', 'Five questions about spiritual gifts', 'a', '2 Corinthians 6:14-16 lists these five contrasting pairs to emphasize the incompatibility of believers being bound with unbelievers.'),
('2 Corinthians', 6, 'adults', 6, 'What does Paul say about the heart of the apostles toward the Corinthians?', 'Our mouth is open unto you, our heart is enlarged — ye are not straitened in us but ye are straitened in your own bowels', 'He has closed his heart to them', 'He has grown indifferent toward them', 'He has transferred his affection to another church', 'a', '2 Corinthians 6:11-12 — "O ye Corinthians, our mouth is open unto you, our heart is enlarged. Ye are not straitened in us, but ye are straitened in your own bowels."'),
('2 Corinthians', 6, 'adults', 7, 'What recompence (return) does Paul ask from the Corinthians?', 'Be ye also enlarged — open your hearts to us as we have opened ours to you', 'Send a large financial gift', 'Build a monument in his honour', 'Send workers to help his ministry', 'a', '2 Corinthians 6:13 — "Now for a recompence in the same, (I speak as unto my children,) be ye also enlarged."'),
('2 Corinthians', 6, 'adults', 8, 'What comprehensive promise does God make in verses 16-18?', 'I will dwell in them, walk in them, be their God; they shall be my people; I will receive you; I will be a Father unto you, ye shall be my sons and daughters', 'He will make them wealthy and powerful', 'He will give them political authority', 'He will remove all suffering from their lives', 'a', '2 Corinthians 6:16-18 — God promises indwelling presence, covenant relationship, reception, and familial belonging, drawing from Leviticus 26:12, Isaiah 52:11, and 2 Samuel 7:14.');

-- ═══ 2 Corinthians Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Corinthians', 7, 'kids', 1, 'What kind of sorrow makes us come back to God?', 'Godly sorrow (being sorry because we disobeyed God)', 'Being sorry we got caught', 'Being angry at other people', 'Being sad about losing a toy', 'a', '2 Corinthians 7:10 — "For godly sorrow worketh repentance to salvation not to be repented of."'),
('2 Corinthians', 7, 'kids', 2, 'Who brought good news to Paul about the Corinthians?', 'Titus', 'Peter', 'Barnabas', 'Silas', 'a', '2 Corinthians 7:6-7 — "Nevertheless God, that comforteth those that are cast down, comforted us by the coming of Titus."'),
('2 Corinthians', 7, 'kids', 3, 'Was Paul glad he had written a strong letter to the Corinthians?', 'Yes, because it helped them repent and turn back to God', 'No, he wished he had never written it', 'He didn''t care either way', 'He was angry about it', 'a', '2 Corinthians 7:9 — "Now I rejoice, not that ye were made sorry, but that ye sorrowed to repentance."'),
-- Teens
('2 Corinthians', 7, 'teens', 1, 'What does Paul urge them to do since they have God''s promises?', 'Cleanse themselves from all filthiness of the flesh and spirit, perfecting holiness in the fear of God', 'Celebrate with feasts and parties', 'Withdraw from all social activities', 'Focus entirely on earning money', 'a', '2 Corinthians 7:1 — "Having therefore these promises, dearly beloved, let us cleanse ourselves from all filthiness of the flesh and spirit, perfecting holiness in the fear of God."'),
('2 Corinthians', 7, 'teens', 2, 'How did God comfort Paul when he was cast down?', 'By the coming of Titus, and by the consolation wherewith Titus was comforted in them', 'By sending an angel with a message', 'By giving him a vision of heaven', 'By removing all his enemies', 'a', '2 Corinthians 7:6-7 — "Nevertheless God, that comforteth those that are cast down, comforted us by the coming of Titus; And not by his coming only, but by the consolation wherewith he was comforted in you."'),
('2 Corinthians', 7, 'teens', 3, 'What is the difference between godly sorrow and worldly sorrow?', 'Godly sorrow worketh repentance to salvation not to be repented of; but the sorrow of the world worketh death', 'There is no difference between them', 'Worldly sorrow is more intense than godly sorrow', 'Godly sorrow is weaker than worldly sorrow', 'a', '2 Corinthians 7:10 — "For godly sorrow worketh repentance to salvation not to be repented of: but the sorrow of the world worketh death."'),
('2 Corinthians', 7, 'teens', 4, 'What did the Corinthians'' godly sorrow produce in them?', 'Carefulness, clearing of themselves, indignation, fear, vehement desire, zeal, and revenge (vindication)', 'Laziness and indifference', 'Pride and self-righteousness', 'Depression and hopelessness', 'a', '2 Corinthians 7:11 — "For behold this selfsame thing, that ye sorrowed after a godly sort, what carefulness it wrought in you, yea, what clearing of yourselves, yea, what indignation, yea, what fear, yea, what vehement desire, yea, what zeal, yea, what revenge!"'),
('2 Corinthians', 7, 'teens', 5, 'How did Titus feel about the Corinthians?', 'His inward affection was more abundant toward them, remembering their obedience and how they received him with fear and trembling', 'He was angry and disappointed', 'He was afraid to return to them', 'He had no particular feelings about them', 'a', '2 Corinthians 7:15 — "And his inward affection is more abundant toward you, whilst he remembereth the obedience of you all, how with fear and trembling ye received him."'),
-- Adults
('2 Corinthians', 7, 'adults', 1, 'What twofold cleansing does Paul call for in verse 1?', 'Cleansing from all filthiness of the flesh and spirit — both outward behaviour and inward attitudes', 'Cleansing only from spiritual sins', 'Cleansing only from physical sins', 'Cleansing through ritual washing only', 'a', '2 Corinthians 7:1 — "Let us cleanse ourselves from all filthiness of the flesh and spirit, perfecting holiness in the fear of God."'),
('2 Corinthians', 7, 'adults', 2, 'What does Paul say about his boasting regarding the Corinthians to Titus?', 'He was not ashamed — his boasting to Titus proved true, just as all things he spoke were truth', 'He regretted exaggerating about them', 'He never mentioned them to Titus', 'He criticised them before Titus', 'a', '2 Corinthians 7:14 — "For if I have boasted any thing to him of you, I am not ashamed; but as we spake all things to you in truth, even so our boasting, which I made before Titus, is found a truth."'),
('2 Corinthians', 7, 'adults', 3, 'What does Paul say about the sorrow his letter caused?', 'He did repent at first, but now rejoices — not that they were made sorry but that they sorrowed to repentance after a godly manner', 'He deeply regrets ever sending the letter', 'He wished the letter had been harsher', 'He plans to send an even more severe letter', 'a', '2 Corinthians 7:8-9 — "For though I made you sorry with a letter, I do not repent, though I did repent: for I perceive that the same epistle hath made you sorry, though it were but for a season. Now I rejoice, not that ye were made sorry, but that ye sorrowed to repentance."'),
('2 Corinthians', 7, 'adults', 4, 'What does Paul say about the Corinthians'' sorrow being after a godly manner?', 'They received damage by Paul in nothing — godly sorrow caused no spiritual harm but led to genuine repentance', 'It caused them to leave the church', 'It made them bitter toward Paul', 'It led them to reject the gospel', 'a', '2 Corinthians 7:9 — "Now I rejoice, not that ye were made sorry, but that ye sorrowed to repentance: for ye were made sorry after a godly manner, that ye might receive damage by us in nothing."'),
('2 Corinthians', 7, 'adults', 5, 'What seven fruits of godly repentance does Paul list in verse 11?', 'Carefulness, clearing of themselves, indignation, fear, vehement desire, zeal, and revenge (vindication of justice)', 'Faith, hope, love, joy, peace, patience, and kindness', 'Wisdom, understanding, counsel, might, knowledge, fear, and delight', 'Poverty, chastity, obedience, prayer, fasting, alms, and pilgrimage', 'a', '2 Corinthians 7:11 — "What carefulness it wrought in you, yea, what clearing of yourselves, yea, what indignation, yea, what fear, yea, what vehement desire, yea, what zeal, yea, what revenge!"'),
('2 Corinthians', 7, 'adults', 6, 'Why did Paul write the severe letter?', 'Not for his cause that had done the wrong, nor for his cause that suffered wrong, but that their care for Paul might appear unto them in the sight of God', 'Primarily to punish the offender', 'To assert his apostolic authority', 'To demand financial compensation', 'a', '2 Corinthians 7:12 — "Wherefore, though I wrote unto you, I did it not for his cause that had done the wrong, nor for his cause that suffered wrong, but that our care for you in the sight of God might appear unto you."'),
('2 Corinthians', 7, 'adults', 7, 'What was Paul''s emotional state when he arrived in Macedonia?', 'His flesh had no rest — without were fightings, within were fears; but God comforted him by the coming of Titus', 'He was joyful and at complete peace', 'He was angry at the Corinthians', 'He was indifferent about everything', 'a', '2 Corinthians 7:5-6 — "For, when we were come into Macedonia, our flesh had no rest, but we were troubled on every side; without were fightings, within were fears. Nevertheless God, that comforteth those that are cast down, comforted us by the coming of Titus."'),
('2 Corinthians', 7, 'adults', 8, 'What does Paul conclude about his confidence in the Corinthians?', 'He has confidence in them in all things — he rejoiceth the more exceedingly', 'He has lost all trust in them', 'He is cautiously optimistic but uncertain', 'He will withhold judgment until his next visit', 'a', '2 Corinthians 7:16 — "I rejoice therefore that I have confidence in you in all things."');
